-- Fase 11: Traduccion al espanol neutro del catalogo de ejercicios (name, description,
-- equipment_required) para las 194 filas cargadas originalmente desde
-- seed_exercises_lattice.sql. No toca category ni los campos typical_*/is_benchmark.
-- Matchea por el nombre ORIGINAL en ingles, asi que ejercicios propios que un
-- entrenador haya agregado o editado via la UI no se ven afectados.
--
-- Correr en el SQL Editor de Supabase.

update exercises set name = '1 min activo / 1 min descanso', description = 'Intervalos de intensidad media estructurados con proporcion trabajo-descanso 1:1. Escala durante 1 minuto, descansa 1 minuto, y repite durante varias series. Objetivo: Estresar tu sistema de capacidad aerobica con intervalos que se vuelven progresivamente mas dificiles de recuperar hacia el final del entrenamiento. Descanso: 60 s entre series', equipment_required = '["Tablero de circuitos"]' where name = '1 On 1 Off';
update exercises set name = '1 min activo / 2 min descanso', description = 'Intervalos de intensidad media estructurados con proporcion trabajo-descanso 1:2. Escala durante 1 minuto, descansa 2 minutos, y repite durante varias series. Objetivo: Estresar tu sistema de capacidad aerobica con intervalos que permiten mayor recuperacion, construyendo una base solida de resistencia. Descanso: 2 min entre series', equipment_required = '["Tablero de circuitos"]' where name = '1 On 2 Off';
update exercises set name = '10 min activo / 10 min descanso', description = 'Escala de forma continua durante 10 minutos a intensidad muy baja, seguido de descanso, repetido durante varias series en rutas o circuitos. Objetivo: Promover la recuperacion y el flujo sanguineo mediante volumen de escalada de baja intensidad, reconstruyendo la base de resistencia sin agregar estres significativo de entrenamiento. Descanso: 10 min entre series', equipment_required = '["Tablero de circuitos"]' where name = '10 On 10 Off';
update exercises set name = '5 min activo / 3 min descanso', description = 'Escala de forma continua durante 5 minutos a intensidad muy baja, seguido de descanso, repetido durante varias series en rutas o circuitos. Objetivo: Promover la recuperacion mediante intervalos de escalada suave, aumentando el flujo sanguineo para ayudar a la reparacion de tejidos mientras se construye la base de resistencia. Descanso: 3 min entre series', equipment_required = '["Tablero de circuitos"]' where name = '5 On 3 Off';
update exercises set name = '50:50 - De facil a moderado', description = 'Alterna entre 15 movimientos faciles y 15 movimientos moderados en cada repeticion, practicando la habilidad de cambiar de intensidad a mitad de la escalada. Objetivo: Desarrollar la capacidad aerobica mientras se aprende a adaptar el ritmo y el estilo de escalada entre secciones de distinta intensidad. Descanso: 10 min entre series', equipment_required = '["Tablero de circuitos"]' where name = '50:50 - Easy to Mod';
update exercises set name = '50:50 - De moderado a facil', description = 'Comienza cada repeticion en una ruta moderada durante 15 movimientos, luego cambia a escalada mas facil durante los 15 movimientos restantes. Objetivo: Desarrollar la capacidad aerobica mientras se aprende a manejar el bombeo y a transicionar entre intensidades de escalada. Descanso: 10 min entre series', equipment_required = '["Tablero de circuitos"]' where name = '50:50 - Mod to Easy';
update exercises set name = '8 min activo / 5 min descanso', description = 'Escala de forma continua durante 8 minutos a intensidad muy baja, seguido de descanso, repetido durante varias series en rutas o circuitos. Objetivo: Apoyar la recuperacion y la base de resistencia mediante intervalos de escalada de baja intensidad y duracion moderada, aumentando el flujo sanguineo sin sobrecargar el sistema. Descanso: 5 min entre series', equipment_required = '["Tablero de circuitos"]' where name = '8 On 5 Off';
update exercises set name = 'Kilometraje de Boulder AC', description = 'Escala 20 boulders muy faciles a baja intensidad, priorizando el ritmo y el movimiento fluido en todo momento. Objetivo: Desarrollar la capacidad aerobica y la capilarizacion del antebrazo mediante boulder de alto volumen y muy baja intensidad.', equipment_required = '["Pared boulder"]' where name = 'AC Boulder Mileage';
