update exercises set name = 'ARC Medio', description = 'Escala de forma continua durante 20 minutos a intensidad muy baja, manteniendo un movimiento facil en rutas o circuitos sin acercarte al fallo. Objetivo: Apoyar la recuperacion activa y la construccion de la base aerobica mediante un bloque de duracion media de escalada facil.', equipment_required = '["Tablero de circuitos"]' where name = 'ARC Medium';
