update exercises set name = 'Rutina de Calistenia de 10 Minutos para Escaladores', description = 'Completa un circuito de calistenia de 10 minutos trabajando cada ejercicio con un tempo de 30 segundos activo, 30 segundos de descanso. Objetivo: Esta rutina guiada de calistenia de 10 minutos para escaladores cubre todas las bases. Funciona como un calentamiento completo de cuerpo entero antes de una sesion de escalada exigente, o como entrenamiento minimalista independiente cuando estas en movimiento. El circuito esta disenado especificamente para mejorar la tension corporal, la movilidad de cadera y la estabilidad del hombro, sin necesidad de gimnasio. Descanso: 30 segundos', equipment_required = '["Colchoneta"]' where name = '10-Minute Calisthenics Routine for Climbers';
