update exercises set name = 'Flexiones de Potencia', description = 'Este entrenamiento se centra en flexiones de potencia. Objetivo: Construir fuerza de empuje maxima en pecho, triceps y hombros, manteniendo el equilibrio muscular alrededor de la articulacion del hombro y reduciendo el riesgo de lesion. Descanso: 5 min entre series', equipment_required = '["Peso corporal"]' where name = 'Power Press Ups';
