update exercises set name = 'Zancada Caminando con Mancuernas - Fuerza', description = 'Completa la zancada caminando con mancuernas dentro de un estimulo de fuerza. Objetivo: Desarrollar fuerza del tren inferior en cuadriceps, gluteos e isquiotibiales, mejorando tu capacidad de generar fuerza a traves de pies y piernas mientras escalas. Descanso: 3 min entre series', equipment_required = '["Mancuernas"]' where name = 'Walking Dumbbell Lunge Strength';
