update exercises set name = '4x4', description = 'Escala 4 boulders seguidos con poco o ningun descanso entre problemas, luego descansa antes de repetir durante varias series. Objetivo: Desarrollar la potencia aerobica mediante esfuerzos de alta intensidad con descanso limitado, usando movimiento variado de boulder para impulsar el rendimiento sostenido. Descanso: 5 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = '4x4s';
update exercises set name = '6 en 6', description = 'Completa 6 boulders al minuto en varias series. El marco de tiempo comprimido genera fatiga rapida. Objetivo: Desarrollar produccion anaerobica repetida con cada boulder completado al minuto. Descanso: 5 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = '6 in 6';
update exercises set name = 'Test de Repeticiones al 60%', description = 'Cuelgate al 60% de tu maximo a dos brazos con un ciclo de 7 segundos activo, 3 segundos de descanso, y continua hasta el fallo. Registra tu tiempo total hasta el agotamiento. Objetivo: Testear y establecer una referencia de tu capacidad de resistencia del antebrazo a una intensidad submaxima estandarizada.', equipment_required = '["Fingerboard"]' where name = '60% Repeater Test';
update exercises set name = 'Proyecto de Capacidad Anaerobica', description = 'Repite un boulder especifico de proyecto o replica en varias series, escalando con enfoque de rendimiento. Objetivo: Transferir las ganancias de capacidad anaerobica a las demandas reales o especificas del proyecto. Descanso: 5 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'AnCap Project';
update exercises set name = 'Dobles de Boulder', description = 'Escala un boulder dificil, descanso breve, luego repitelo de inmediato. Completa varias series de dobles. Objetivo: Desarrollar la capacidad anaerobica y la habilidad de mantener la intensidad en esfuerzos repetidos de alta potencia. Descanso: 4 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Boulder Doubles';
update exercises set name = 'Kilometraje de Boulder - Intervalos Forzados', description = 'Completa un numero alto de boulders de rango medio en varias series con descansos cortos, asegurando una amplia variedad de movimiento. Objetivo: Impulsar la potencia aerobica completando un alto volumen de boulders de intensidad media a alta bajo fatiga. Descanso: 10 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Boulder Mileage Forced Intervals';
update exercises set name = 'Triples de Boulder', description = 'Escala un boulder dificil 3 veces por serie con descanso corto entre repeticiones, completando varias series. Objetivo: Desarrollar la capacidad anaerobica mediante esfuerzos repetidos de alta intensidad que acumulan fatiga a traves de las repeticiones y del transcurso de la sesion. Descanso: 5 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Boulder Triples';
update exercises set name = '30 Movimientos Fraccionados', description = 'Divide una ruta o circuito de 30 movimientos en 3 secciones de 10 movimientos, descansando 20 segundos entre secciones. Descansa 6 minutos entre vueltas completas. Objetivo: Entrenar el rendimiento en escalada sostenida dividiendo una ruta de nivel limite en secciones completables. Descanso: 6 min entre series', equipment_required = '["Tablero de circuitos"]' where name = 'Broken 30s';
update exercises set name = 'Boulders Extendidos', description = 'Repite un boulder largo de 16 movimientos en varias series. Espera estar luchando hacia el final. Objetivo: Impulsar la tolerancia a secuencias sostenidas de alta intensidad que conectan el boulder con el esfuerzo de la longitud de una ruta. Descanso: 5 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Extended Boulders';
update exercises set name = '5 Series Mas Dificiles', description = 'Escala 5 rutas o circuitos dificiles de 30-40 movimientos de mas facil a mas dificil. Objetivo: Mejorar la potencia aerobica mediante esfuerzos de longitud de ruta desafiantes que te preparan para las demandas de la escalada deportiva dificil. Descanso: 10 min entre series', equipment_required = '["Tablero de circuitos"]' where name = 'Harder 5 Sets';
update exercises set name = 'Boulders Enlazados', description = 'Repite un boulder largo bien ensayado (alrededor de 14 movimientos) en varias series. Objetivo: Mejorar la tolerancia a secuencias sostenidas de alta intensidad que exigen un esfuerzo prolongado. Descanso: 5 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Linked Boulders';
update exercises set name = 'A Vista', description = 'Intenta 4 rutas en o cerca de tu nivel a vista de punta, dedicando tiempo a leer la ruta y prepararte antes de cada intento unico. Objetivo: Entrenar la potencia aerobica junto con las habilidades tacticas y psicologicas necesarias para rendir en intentos a vista. Descanso: 20 min entre series', equipment_required = '["Pared de dificultad"]' where name = 'Onsighting';
update exercises set name = 'Dobles de Ruta', description = 'Escala una ruta dificil, descansa brevemente en la pared o baja, luego repitela de inmediato. Completa 5 vueltas dobles con descanso completo entre series. Objetivo: Construir potencia aerobica sostenida replicando esfuerzos mas largos, asegurando un alto volumen de escalada fatigante. Descanso: 10 min entre series', equipment_required = '["Tablero de circuitos"]' where name = 'Route Doubles';
update exercises set name = 'Proyectando Rutas', description = 'Dedica el entrenamiento a intentar rutas en el limite de tu capacidad, ya sean proyectos o escaladas nuevas dificiles. Apunta a 150-250 movimientos en total. Objetivo: Desarrollar la resistencia de potencia de alto nivel intentando rutas dificiles, construyendo la capacidad de rendir a este nivel.', equipment_required = '["Tablero de circuitos"]' where name = 'Route Projecting';
update exercises set name = 'Piramide de Rutas', description = 'Escala 8 rutas en piramide, empezando facil, subiendo hasta tu nivel mas dificil, y luego bajando de nuevo. Si tienes menos series, detente en la cima. Objetivo: Entrenar la potencia aerobica completando escalada de rutas de alto volumen a traves de intensidades ascendentes y descendentes. Descanso: 10 min entre series', equipment_required = '["Tablero de circuitos"]' where name = 'Route Pyramid';
update exercises set name = 'Eficiencia en Board', description = 'Refina la beta y elimina movimientos innecesarios en problemas de board que ya conoces. Enfocate en escalar de la manera mas limpia y eficiente posible. Objetivo: Aumentar la eficiencia tecnica y la economia energetica en terreno vertical pronunciado sin necesidad de ganar fuerza.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Board Efficiency';
update exercises set name = 'Esfuerzos Maximos en Board', description = 'Trabaja a verdadera intensidad de alto nivel en un training board, intentando problemas que tomaran varios entrenamientos completar. Objetivo: Aumentar la fuerza maxima y la produccion de potencia en terreno de board pronunciado.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Board Max Efforts';
update exercises set name = 'Esfuerzos Maximos en Board - Extendido', description = 'Un entrenamiento extendido de board a verdadera intensidad de alto nivel, con mas tiempo para trabajar problemas limite y acumular intentos de calidad. Objetivo: Aumentar la fuerza maxima y la produccion de potencia con un mayor volumen de esfuerzo de alto nivel.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Board Max Efforts - Extended';
update exercises set name = 'Pausas en Board', description = 'En cada movimiento de un problema de board pronunciado, suelta los pies y manten 3 segundos antes de volver a colocarlos. Manten el control en todo momento. Objetivo: Desarrollar fuerza de contacto, estabilidad de hombro y control posicional bajo carga. Descanso: 5 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Board Pauses';
update exercises set name = 'Encadenando en Board', description = 'Intenta problemas de board justo por debajo de tu limite que puedas completar en pocos intentos. Apunta a encadenes de calidad mas que a proyectos de largo plazo. Objetivo: Construir confianza y capacidad de rendimiento en terreno de board pronunciado mediante la ejecucion exitosa de problemas dificiles.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Board Sending';
update exercises set name = 'Sesion de Board', description = 'Escala problemas dificiles en un training board con 3 intentos por problema y recuperacion completa entre series. Objetivo: Construir fuerza y potencia de alto nivel mientras mejoras tu capacidad de ejecutar movimientos dificiles en terreno de board pronunciado. Descanso: 6 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Board Session';
update exercises set name = 'Volumen de Board', description = 'Acumula un numero alto de problemas de board desafiantes a intensidad submaxima, completando cada uno en 1-3 intentos antes de continuar. Objetivo: Construir capacidad de trabajo y resistencia de fuerza en terreno pronunciado mediante un esfuerzo constante y de alto volumen.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Board Volume';
update exercises set name = 'Circuitos de Boulder', description = 'Sigue un circuito o elige boulders dentro de un rango de grado dado, trabajando problemas justo por encima de tu nivel a vista con series estructuradas. Objetivo: Construir fuerza submaxima y variedad de movimiento mediante un esfuerzo consistente y repetible a traves de una gama de problemas. Descanso: 6 min entre series', equipment_required = '["Tablero de circuitos"]' where name = 'Boulder Circuits';
update exercises set name = 'Enfoque de Boulder', description = 'Enfocate en un tema tecnico o estilo de movimiento especifico durante todo el entrenamiento, segun indique tu entrenador. Ejecuta con precision. Objetivo: Abordar debilidades tecnicas individuales mientras se mantiene un estimulo de fuerza. Descanso: 3 min entre series', equipment_required = '["Pared boulder"]' where name = 'Boulder Focus';
update exercises set name = 'Esfuerzos Maximos de Boulder', description = 'Intenta problemas de boulder en el limite de tu capacidad con recuperacion completa entre intentos. Los problemas pueden tomar varios entrenamientos completar. Objetivo: Aumentar la fuerza maxima y la produccion de potencia.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Boulder Max Efforts';
update exercises set name = 'Kilometraje de Boulder', description = 'Completa 20 boulders en una hora a una intensidad desafiante pero manejable, apuntando a encadenar o completar cada uno en dos intentos. Objetivo: Construir capacidad y tolerancia para boulder sostenido de alto volumen a una intensidad media controlada.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Boulder Mileage';
update exercises set name = 'Juego de Boulder', description = 'Experimenta con el movimiento en un estimulo de baja presion creando o modificando problemas. Prueba estilos, betas y posiciones corporales poco familiares. Objetivo: Expandir el vocabulario de movimiento, la coordinacion y la resolucion creativa de problemas.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Boulder Play';
update exercises set name = 'Piramide de Boulder', description = 'Escala problemas progresivamente mas dificiles hasta tu maximo, luego trabaja de vuelta hacia grados mas faciles. Si tienes menos series, detente en la cima. Objetivo: Desarrollar la fuerza y el manejo de la fatiga mediante variacion de intensidad controlada a traves de una piramide estructurada. Descanso: 2 min 30 s entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Boulder Pyramid';
update exercises set name = 'Encadenando Boulder', description = 'Intenta problemas que sean dificiles pero alcanzables en pocos intentos. Prioriza los encadenes exitosos y la ejecucion precisa. Objetivo: Reforzar la consistencia de rendimiento mientras se construye fuerza y potencia submaxima.', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Boulder Sending';
update exercises set name = 'Campus - 3 Movimientos', description = 'Realiza 3 movimientos maximos de campus por serie en varias series, enfocandote en velocidad y contacto controlado en cada peldano. Objetivo: Aumentar la potencia de traccion maxima y la fuerza de contacto mediante secuencias de campus maximas extendidas. Descanso: 3 min entre series', equipment_required = '["Campus board"]' where name = 'Campus - 3 Moves';
update exercises set name = 'Sesion de Competencia - Final', description = 'Simula una competencia estilo final con 4 minutos por problema y recuperacion completa entre boulders. Maximiza la calidad por intento. Objetivo: Desarrollar el rendimiento maximo bajo demanda psicologica maxima y presion de tiempo. Descanso: 10 min entre series', equipment_required = '["Pared boulder"]' where name = 'Comp Session - Final';
update exercises set name = 'Sesion de Competencia - Semifinal', description = 'Replica las demandas de una competencia de semifinal con 5 minutos por problema y descanso estructurado. Escala bajo presion. Objetivo: Mejorar la compostura, la precision y la ejecucion a alta intensidad bajo restricciones estilo competencia. Descanso: 5 min entre series', equipment_required = '["Pared boulder"]' where name = 'Comp Session - Semi Final';
update exercises set name = 'Eliminados', description = 'Escala problemas con presas eliminadas para forzar soluciones creativas y dinamicas. Adopta la resolucion de problemas y el movimiento poco familiar. Objetivo: Desarrollar coordinacion, precision y adaptabilidad mediante escalada restringida. Descanso: 2 min entre series', equipment_required = '["Pared boulder"]' where name = 'Eliminates';
update exercises set name = 'Encadenando a Vista (Flash)', description = 'Comprometete por completo con esfuerzos de un solo intento a vista (flash) en problemas de tu grado de flash a traves de una variedad de estilos. Lee la ruta con cuidado, luego da el 100%. Objetivo: Mejorar la capacidad de flash, la toma de decisiones y la ejecucion bajo alta presion. Descanso: 3 min entre series', equipment_required = '["Pared boulder"]' where name = 'Flashing Boulders';
update exercises set name = 'Esfuerzos Maximos de Boulder Sin Pies', description = 'Campusea los problemas de boulder de 4 movimientos mas dificiles posibles en presas grandes sin usar los pies. Usa movimientos potentes y evita los lock offs estaticos. Objetivo: Aumentar la fuerza de traccion, la tension y la precision a intensidad maxima sin asistencia del tren inferior. Descanso: 10 min entre series', equipment_required = '["Pared boulder"]' where name = 'Footless Boulder Max Efforts';
update exercises set name = 'Referencias de MoonBoard', description = 'Intenta problemas de referencia desafiantes de MoonBoard con 3 intentos por problema y recuperacion completa entre series. Objetivo: Mejorar la fuerza de traccion maxima y la resolucion rapida de problemas en terreno pronunciado y estandarizado. Descanso: 6 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'MoonBoard Benchmarks';
update exercises set name = 'Intervalos de Fuerza', description = 'Repite boulders dificiles pero submaximos en series estructuradas con recuperacion completa. Opera cerca de tu umbral de fuerza superior en todas las series. Objetivo: Aumentar la resistencia de fuerza y la produccion de fuerza repetible. Descanso: 5 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Strength Intervals';
update exercises set name = 'Tension - Manos Fijas', description = 'Manten las manos fijas en dos presas mientras trasladas los pies a traves de la pared en terreno pronunciado, generando el movimiento desde el tren inferior y el core. Objetivo: Desarrollar el manejo de la tension, la fuerza posicional y la transferencia eficiente de fuerza a traves de los pies en terreno pronunciado. Descanso: 3 min entre series', equipment_required = '["Tension/Kilter/Moonboard"]' where name = 'Tension - Pinned Hands';
update exercises set name = 'Flexibilidad de Tobillo', description = 'Un entrenamiento guiado de estiramientos de gemelos, elevaciones de talon tipo burro y estiramientos de pescador para aumentar el rango de movimiento del tobillo. Objetivo: Mejorar la dorsiflexion del tobillo para que puedas bajar mas el talon en las presas de pie, aumentando el area de contacto y la friccion para escalada en placa y vertical. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Ankle Flexibility';
update exercises set name = 'Rotacion Externa con Banda - Contrae y Relaja', description = 'Multiples series de ciclos de contrae y relaja. Objetivo: Usar tecnicas de contrae y relaja para mejorar el rango de movimiento en el manguito rotador y el hombro posterior, mejorando la calidad del movimiento y la salud del hombro para la escalada. Descanso: 1 min 30 s entre series', equipment_required = '["Banda elastica"]' where name = 'Banded External Rotation - Contract Relax';
update exercises set name = 'Elevacion en Barra - Lateral', description = 'Realiza elevaciones laterales de pierna controladas para fortalecer los abductores de cadera cerca de su rango final de movimiento. Objetivo: Construir fuerza del abductor de cadera en el rango final, mejorando la elevacion lateral activa de la pierna para colocaciones de pie amplias mientras escalas. Descanso: 60 s entre series', equipment_required = '["Barra"]' where name = 'Barre Lift - Lateral';
update exercises set name = 'Estiramiento de Biceps - Estatico Pasivo', description = 'Manten un estiramiento estatico de biceps usando la posicion de tu cuerpo para sostener el estiramiento durante sujeciones cronometradas. Objetivo: Mejorar la flexibilidad de biceps y codo, reduciendo la rigidez de la escalada y apoyando la extension completa del brazo en la pared. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Bicep Stretch - Static Passive';
update exercises set name = 'Sentadillas Cosaco - Estiramiento con Tempo', description = 'Realiza sentadillas cosaco siguiendo un temporizador de tempo a traves de las fases de bajada, pausa y subida para estirar los aductores y las caderas. Objetivo: Desarrollar movilidad lateral de cadera y flexibilidad de aductores bajo control, mejorando la capacidad de alcanzar presas de pie amplias. Descanso: 1 min 30 s entre series', equipment_required = '["Peso corporal"]' where name = 'Cossack Squats - Tempo Stretch';
update exercises set name = 'Pullover de Dorsales con Mancuerna - Estiramiento con Tempo', description = 'Realiza pullovers de dorsales con mancuerna siguiendo un temporizador a traves de las fases de bajada, pausa y subida para estirar los dorsales y los hombros. Objetivo: Aumentar la flexibilidad por encima de la cabeza de dorsales y hombros mediante trabajo de tempo cargado, mejorando el alcance y el movimiento por encima de la cabeza en la pared. Descanso: 1 min 30 s entre series', equipment_required = '["Mancuernas"]' where name = 'Dumbbell Lat Pullover - Tempo Stretch';
update exercises set name = 'Estiramientos de Dedos - Estatico Pasivo', description = 'Multiples series de estiramientos de dedos pasivos de 60 s. Objetivo: Mejorar la flexibilidad de flexores y extensores de los dedos, apoyando la salud de los dedos y reduciendo el riesgo de lesion por las altas demandas de carga de la escalada. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Finger stretches - Static Passive';
update exercises set name = 'Fire Hydrant - Pierna Flexionada - Desarrollo de Fuerza', description = 'Realiza repeticiones de fire hydrant con pierna flexionada para fortalecer los gluteos y los rotadores externos de cadera cerca del rango final de movimiento. Objetivo: Construir fuerza de gluteos y rotadores de cadera en el rango final, mejorando la estabilidad y el control en posiciones de escalada con rotacion externa. Descanso: 1 min 30 s entre series', equipment_required = '["Bloque de yoga"]' where name = 'Fire Hydrant - Bent Leg - Strength Development';
update exercises set name = 'Mantenimiento de Flexibilidad', description = 'Una rutina guiada de mantenimiento de cuerpo entero con patadas, pancake, rana, paloma, estiramiento de sofa, estiramiento de gemelo, estiramiento de pecho y estiramiento de dorsal a baja intensidad. Objetivo: Mantener las ganancias de flexibilidad durante semanas de descarga y taper, previniendo la regresion del rango de movimiento sin agregar carga de entrenamiento. Descanso: 5 s entre series', equipment_required = '["Peso corporal"]' where name = 'Flexibility Maintenance';
update exercises set name = 'Flexibilidad de Antebrazo', description = 'Un entrenamiento guiado de estiramientos de extensores y flexores de muneca para aumentar la flexibilidad de antebrazo y muneca. Objetivo: Mejorar el rango de movimiento de muneca y antebrazo, apoyando una mayor variedad de posiciones de presa incluyendo undercuts, gastones y regletas planas. Descanso: 30 s entre series', equipment_required = '["Peso corporal"]' where name = 'Forearm Flexibility';
update exercises set name = 'Rana Supina - Estatico Pasivo', description = 'Manten un estiramiento de rana acostado boca arriba, usando la gravedad para asistir la apertura de cadera durante sujeciones cronometradas. Objetivo: Aumentar la flexibilidad de aductores de cadera en una posicion asistida, construyendo rango de ingle para posiciones de escalada con piernas opens. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Frog Supine - Static Passive';
update exercises set name = 'Patadas Frontales - Dinamico', description = 'Realiza patadas frontales controladas para estirar activamente los isquiotibiales y flexores de cadera. Objetivo: Construir flexibilidad dinamica de isquiotibiales y potencia de flexores de cadera, mejorando la capacidad de levantar los pies alto frente al cuerpo mientras escalas. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Front Kicks - Dynamic';
update exercises set name = 'Split Frontal - Nivel 1', description = 'Un entrenamiento de split frontal con varios ejercicios usando peso muerto rumano a una pierna y sujeciones isometricas de zancada larga para desarrollar fuerza y rango mediante estiramientos activo-estaticos. Objetivo: Construir flexibilidad de isquiotibiales y flexores de cadera con fuerza en el rango final, creando una base para la progresion del split frontal y la capacidad de paso alto.', equipment_required = '["Peso corporal"]' where name = 'Front Split - L1';
update exercises set name = 'Pulsos de Split Frontal - Dinamico', description = 'Realiza repeticiones de pulso controladas manteniendo una profundidad exigente de split frontal para fortalecer los musculos en el rango final. Objetivo: Desarrollar fuerza activa y resistencia muscular a una profundidad de split casi maxima, construyendo rango utilizable para posiciones de escalada. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Front Split Pulse - Dynamic';
update exercises set name = 'Gluteos e Isquiotibiales', description = 'Un entrenamiento guiado de estiramiento de sofa, pancake de pie, postura de paloma y split lateral ISO para aumentar la flexibilidad de gluteos e isquiotibiales. Objetivo: Mejorar el rango de cadera, gluteo e isquiotibial para que puedas colocar los pies mas alto en la pared manteniendo las caderas cerca, aumentando la economia de movimiento. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Glutes and Hamstrings';
update exercises set name = 'Good Morning Sentado - Estiramiento con Tempo', description = 'Realiza good mornings sentado siguiendo un temporizador de tempo a traves de las fases de bajada, pausa y subida para estirar los isquiotibiales. Objetivo: Mejorar la flexibilidad de isquiotibiales y el rango de flexion de tronco mediante trabajo de tempo controlado, apoyando los heel hooks y las colocaciones de pie alto. Descanso: 1 min 30 s entre series', equipment_required = '["Barra"]' where name = 'Good Morning - Seated - Tempo Stretch';
update exercises set name = 'Estiramiento de Isquiotibiales - Sentado - Estatico Pasivo', description = 'Manten un estiramiento de isquiotibiales sentado usando la posicion del cuerpo y la gravedad para sostener el estiramiento durante sujeciones cronometradas. Objetivo: Aumentar la flexibilidad de isquiotibiales mediante sujeciones pasivas sostenidas, mejorando el rango de flexion de tronco para heel hooks y colocaciones de pie alto. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Hamstring Stretch - Seated - Static Passive';
update exercises set name = 'Aductores de Cadera', description = 'Un entrenamiento guiado de mariposa, split lateral ISO, rana y medio split lateral para aumentar la flexibilidad de los aductores de cadera. Objetivo: Mejorar el alcance lateral de la pierna aumentando la flexibilidad de los aductores, ampliando las opciones de presas de pie y la economia de movimiento en la pared. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Hip Adductors';
update exercises set name = 'Postura de Caballo - ISO - Estatico Activo', description = 'Manten una posicion de sentadilla de caballo en profundidad mientras usas activamente tus musculos para mantener la postura durante sujeciones cronometradas. Objetivo: Construir flexibilidad de aductores y estabilidad de cadera mediante sujeciones activas, mejorando la capacidad de mantener posturas amplias en la pared. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Horse Stance - ISO - Static Active';
update exercises set name = 'Zancada Larga ISO - Estatico Pasivo', description = 'Manten una posicion de zancada larga de forma pasiva, usando la posicion del cuerpo y la gravedad para sostener el estiramiento del flexor de cadera durante sujeciones cronometradas. Objetivo: Alargar los flexores de cadera mediante sujeciones pasivas sostenidas, mejorando el rango de extension de cadera para pasos altos y posiciones de pared pronunciada. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Long Lunge Iso - Static Passive';
update exercises set name = 'Movilidad Matutina', description = 'Un entrenamiento guiado diario en el piso de giro de sabio, postura de cachorro, estiramiento de gemelo en pared, side runner, postura de paloma y sentadilla yogui para movilidad de cuerpo entero. Objetivo: Construir movilidad mediante la practica diaria de baja intensidad, reforzando el habito para apoyar las ganancias de flexibilidad con el tiempo. Descanso: 30 s entre series', equipment_required = '["Peso corporal"]' where name = 'Morning Mobility';
update exercises set name = 'Pancake - Pulsos', description = 'Pulsa hacia un estiramiento profundo de pancake, moviendote a traves del arco de tu posicion de piernas opens por repeticiones. Objetivo: Aumentar la flexibilidad de isquiotibiales y aductores mediante pulsos dinamicos, mejorando el rango de piernas opens para colocaciones de pie amplias. Descanso: 1 min 30 s entre series', equipment_required = '["Peso corporal"]' where name = 'Pancake - Pulses';
update exercises set name = 'Pancake - De Pie - Estatico Pasivo', description = 'Manten un estiramiento de pancake de pie con las piernas bien separadas, usando la gravedad para asistir el pliegue hacia adelante durante sujeciones cronometradas. Objetivo: Aumentar la flexibilidad de isquiotibiales y aductores en una posicion de piernas opens de pie, apoyando el movimiento de piernas amplias y los pasos altos mientras escalas. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Pancake - Standing - Static Passive';
update exercises set name = 'Estiramiento de Pecho - Estatico Pasivo', description = 'Manten un estiramiento pasivo de pecho usando la gravedad o una superficie externa para sostener la posicion de apertura del pecho durante sujeciones cronometradas. Objetivo: Mejorar la flexibilidad de pecho y hombro anterior, reduciendo la rigidez de la escalada y apoyando posiciones de cuerpo abierto en la pared. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Pec Stretch - Static Passive';
update exercises set name = 'Postura de Paloma - Contrae y Relaja', description = 'Alterna entre contraer y relajar los musculos de la cadera en una postura de paloma para facilitar un estiramiento mas profundo con cada ciclo. Objetivo: Mejorar la flexibilidad de gluteo y rotador de cadera usando tecnicas FNP, acelerando las ganancias en la rotacion externa de cadera para la tecnica de escalada. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Pigeon Pose - Contract Relax';
update exercises set name = 'Pulsos y Patadas', description = 'Un entrenamiento guiado diario de patadas laterales, patadas frontales y pulsos de pancake para entrenar la flexibilidad dinamica mediante repeticion de alta frecuencia. Objetivo: Desarrollar rango activo dinamico mediante ejercicios diarios de patadas y pulsos, construyendo flexibilidad utilizable para el movimiento de escalada.', equipment_required = '["Peso corporal"]' where name = 'Pulses and Kicks';
update exercises set name = 'Estiramiento de Cuadriceps - Sentado - Estatico Pasivo', description = 'Manten un estiramiento pasivo de cuadriceps en posicion sentada, reclinandote hacia atras para aumentar y sostener el estiramiento durante sujeciones cronometradas. Objetivo: Alargar los cuadriceps y flexores de cadera mediante sujeciones pasivas, mejorando el rango de flexion de rodilla y extension de cadera para heel hooks y pasos altos. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Quad Stretch - Seated - Static Passive';
update exercises set name = 'Estiramiento Revolver - Estatico Pasivo', description = 'Manten un estiramiento revolver pasivo en medio split para estirar los dorsales y el costado del torso durante sujeciones cronometradas. Objetivo: Aumentar la flexibilidad de dorsales y tronco lateral, mejorando el alcance lateral y el movimiento por encima de la cabeza en la pared. Descanso: 60 s entre series', equipment_required = '["Colchoneta"]' where name = 'Revolver Stretch - Static Passive';
update exercises set name = 'Dislocaciones de Hombro - Estiramiento con Tempo', description = 'Realiza pases circulares de hombro usando un palo o banda, siguiendo un tempo para guiar el movimiento a traves del rango completo. Objetivo: Aumentar la movilidad de hombro y el rango por encima de la cabeza mediante trabajo de tempo controlado, mejorando el alcance y la libertad de movimiento en la pared. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Shoulder Dislocations - Tempo Stretch';
update exercises set name = 'Patadas Laterales - Dinamico', description = 'Realiza patadas laterales controladas para estirar activamente los aductores de cadera a traves de su rango completo. Objetivo: Desarrollar rango de movimiento lateral dinamico de cadera, mejorando la capacidad de colocar los pies amplios con control mientras escalas. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Side Kicks - Dynamic';
update exercises set name = 'Split Lateral - Nivel 1', description = 'Un entrenamiento guiado de split lateral usando sujeciones ISO de postura de caballo y estiramientos de pancake de pie para desarrollar fuerza y rango de aductores de cadera mediante trabajo activo y estatico. Objetivo: Construir rango de split lateral fundamental y fuerza de aductores sin carga externa, creando una base para una mayor progresion de flexibilidad. Descanso: 10 s entre series', equipment_required = '["Peso corporal"]' where name = 'Side Split - L1';
update exercises set name = 'Split Lateral ISO - Estatico Activo', description = 'Manten una posicion de split lateral mientras involucras activamente tus musculos para sostener el estiramiento durante sujeciones cronometradas. Objetivo: Construir fuerza activa y control a la profundidad del split lateral, desarrollando rango de movimiento utilizable para posiciones de escalada amplias. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Side Split Iso - Static Active';
update exercises set name = 'Test de Split Lateral - Sin Apoyo', description = 'Realiza una sujecion ISO de split lateral sin apoyo para registrar tu rendimiento actual de split lateral, con notas y medidas registradas en el tiempo. Objetivo: Establecer una referencia de tu progreso en split lateral mediante un test estandarizado, permitiendote a ti y a tu entrenador seguir las ganancias de flexibilidad en el tiempo.', equipment_required = '["Peso corporal"]' where name = 'Side Split Test - Unsupported';
update exercises set name = 'Estiramiento Sleeper - Estatico Pasivo', description = 'Manten un estiramiento sleeper acostado de lado, usando la gravedad y el otro brazo para sostener un estiramiento posterior del hombro durante sujeciones cronometradas. Objetivo: Mejorar la flexibilidad posterior del hombro y el rango de rotacion interna, reduciendo la rigidez del hombro por la escalada y apoyando una mecanica articular saludable. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Sleeper Stretch - Static Passive';
update exercises set name = 'Peso Muerto Rumano a Una Pierna - Estiramiento con Tempo', description = 'Realiza peso muerto rumano a una pierna siguiendo un temporizador de tempo a traves de las fases de bajada, pausa y subida para estirar los isquiotibiales. Objetivo: Aumentar la flexibilidad de isquiotibiales a una pierna mediante trabajo de tempo controlado, mejorando el rango de pliegue hacia adelante y la capacidad de heel hook. Descanso: 1 min 30 s entre series', equipment_required = '["Peso corporal"]' where name = 'SL-GM - Tempo Stretch';
update exercises set name = 'Sentadillas Split - Estiramiento con Tempo', description = 'Realiza sentadillas split siguiendo un temporizador de tempo a traves de las fases de bajada, pausa y subida para estirar los flexores de cadera y cuadriceps. Objetivo: Desarrollar la longitud del flexor de cadera y la flexibilidad de cuadriceps bajo carga, mejorando la zancada profunda y la capacidad de paso alto en la pared. Descanso: 1 min 30 s entre series', equipment_required = '["Peso corporal"]' where name = 'Split Squats - Tempo Stretch';
update exercises set name = 'Estiramiento de Gemelo en Pared - Estatico Pasivo', description = 'Manten un estiramiento pasivo de gemelo usando una pared para sostener la posicion de estiramiento durante sujeciones cronometradas. Objetivo: Mejorar la flexibilidad de gemelo y tobillo, permitiendo bajadas de talon mas profundas y mejor contacto de pie en las presas de pie. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Wall Calf Stretch - Static Passive';
update exercises set name = 'Estiramiento de Flexor de Cadera en Pared - Estatico Pasivo', description = 'Manten un estiramiento pasivo de flexor de cadera y cuadriceps usando una pared para profundizar el estiramiento durante sujeciones cronometradas. Objetivo: Alargar los flexores de cadera y cuadriceps, mejorando el rango de extension de cadera para pasos altos, mantle y escalada en pared pronunciada. Descanso: 60 s entre series', equipment_required = '["Peso corporal"]' where name = 'Wall Hip Flexor Stretch - Static Passive';
update exercises set name = 'Calentamiento y Vuelta a la Calma', description = 'Una rutina guiada rapida de rotacion interna acostado, postura de paloma, estiramiento de isquiotibiales, postura de caballo ISO, rana y estiramiento de gemelo para uso de calentamiento o vuelta a la calma. Objetivo: Mantener la flexibilidad del tren inferior y preparar las articulaciones para la escalada, adecuado como calentamiento previo al entrenamiento o vuelta a la calma posterior.', equipment_required = '["Peso corporal"]' where name = 'Warm Up and Cool Down';
update exercises set name = 'Estiramiento de Muneca - Estatico Pasivo', description = 'Multiples series de estiramiento de muneca pasivo de 60 s. Objetivo: Mejorar la flexibilidad de flexores y extensores de muneca, apoyando la salud de los dedos y reduciendo el riesgo de lesion por las altas demandas de carga de la escalada. Descanso: 60 s entre series', equipment_required = '[]' where name = 'Wrist Stretch - Static Passive';
update exercises set name = 'F2 Open - Levantamiento - Facil', description = 'Realiza levantamientos de 7 s en agarre F2 open (front two open hand), a baja intensidad para mantener la salud del tejido en varias series. Objetivo: Mantener la carga en F2 open a baja intensidad para promover la salud del tejido y el confort sin acumular fatiga. Descanso: 60 s entre series', equipment_required = '["Regleta de lastre"]' where name = 'F2 Open - Lift - Easy';
update exercises set name = 'F2 Open - Levantamiento - Maximo', description = 'Realizaras levantamientos de 7 s en agarre F2 open, a intensidad casi maxima para fuerza de peak en varias series. Objetivo: Desarrollar la fuerza maxima de dedos en F2 open mediante carga isometrica corta de alta intensidad con recuperacion completa. Descanso: 3 min entre series', equipment_required = '["Regleta de lastre"]' where name = 'F2 Open - Lift - Max';
update exercises set name = 'F2 Open - Levantamiento - Peak', description = 'Completa levantamientos de 5 s en agarre F2 open en varias series. Objetivo: Aumentar la fuerza de peak de dedos en F2 open y el reclutamiento de unidades motoras mediante esfuerzos muy cortos de intensidad maxima. Descanso: 3 min entre series', equipment_required = '["Regleta de lastre"]' where name = 'F2 Open - Lift - Peak';
update exercises set name = 'F2 Open - Levantamiento - Fuerza', description = 'Realizaras levantamientos de 10 s en agarre F2 open en varias series. Objetivo: Aumentar la fuerza de dedos en F2 open mediante carga isometrica de alta intensidad a una duracion desafiante pero sostenible. Descanso: 3 min entre series', equipment_required = '["Regleta de lastre"]' where name = 'F2 Open - Lift - Strength';
update exercises set name = 'F3 Half Crimp - Levantamiento - Maximo', description = 'Este entrenamiento se centra en levantamientos de 7 s en agarre F3 Half crimp (front three half crimp), a intensidad casi maxima para fuerza de peak. Objetivo: Desarrollar la fuerza maxima de dedos en F3 Half crimp mediante carga isometrica corta de alta intensidad con recuperacion completa. Descanso: 3 min entre series', equipment_required = '["Regleta de lastre"]' where name = 'F3 Half - Lift - Max';
update exercises set name = 'F3 Half Crimp - Levantamiento - Fuerza', description = 'Este entrenamiento se centra en levantamientos de 10 s en agarre F3 Half crimp. Objetivo: Aumentar la fuerza de dedos en F3 Half crimp mediante carga isometrica de alta intensidad a una duracion desafiante pero sostenible. Descanso: 3 min entre series', equipment_required = '["Regleta de lastre"]' where name = 'F3 Half - Lift - Strength';
update exercises set name = 'Levantamientos de Reclutamiento de Flexores de Dedos', description = 'Completaras multiples series de levantamientos, aumentando progresivamente la intensidad de muy facil a desafiante. Objetivo: Calentar y reclutar los flexores de dedos antes de un entrenamiento de escalada aumentando gradualmente la carga. Descanso: 2 min entre series', equipment_required = '["Regleta de lastre"]' where name = 'FS Recruitment Lifts';
update exercises set name = 'Half Crimp 4 - Levantamiento - Base', description = 'Realiza levantamientos de 30 s en Half crimp, a intensidad moderada para construir fuerza base en varias series. Objetivo: Construir fuerza base de dedos en Half crimp mediante carga isometrica de mayor duracion a intensidad moderada. Descanso: 3 min entre series', equipment_required = '["Regleta de lastre"]' where name = 'Half 4 - Lift - Foundation';
